using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — shows the two Cosmos-specific EF Core 9 fixes.
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=KEY",
            "CatalogDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // Breaking change 3: EF Core 9 renamed the Cosmos discriminator
            // property from "Discriminator" to "$type".  Existing documents
            // already store "Discriminator", so opt back in to the old name
            // to avoid data-mismatch / query failures.
            b.HasDiscriminator<string>("Discriminator");
        });
    }

    // Breaking change 4: EF Core 9 Cosmos provider no longer supports
    // synchronous I/O — ToList(), First(), SaveChanges(), etc. throw
    // InvalidOperationException.  All Cosmos calls must be async.
    //
    // BEFORE (EF Core 8 — sync, now broken):
    //   var items = db.Products.Where(p => p.Price > 10).ToList();
    //   db.Products.Add(new Product { ... });
    //   db.SaveChanges();
    //
    // AFTER (EF Core 9 — async):
    public async Task<List<Product>> GetExpensiveProductsAsync()
        => await Products.Where(p => p.Price > 10).ToListAsync();

    public async Task AddProductAsync(Product product)
    {
        Products.Add(product);
        await SaveChangesAsync();
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Category { get; set; } = default!;
    public decimal Price { get; set; }
}

